import React, { useMemo } from 'react';
import { polarToCartesian } from './utils/geometry';
import type { SpiralArrowsProps } from './InwardSpiralArrows';

export const OutwardSpiralArrows: React.FC<SpiralArrowsProps> = ({
  segments, radii, neutralOutside, direction, styles, hoveredPerspectiveIdx, selectedPerspectiveIdx, focusAnimatingIdx,
}) => {
  const arrows = useMemo(() => {
    const pos = segments.positive.filter(s => s.perspectiveIndex !== -1);
    const neg = segments.negative.filter(s => s.perspectiveIndex !== -1);
    if (pos.length < 2 || neg.length < 2) return [];

    const cw = direction !== 'left';

    const posR = (radii.innerStart + radii.innerEnd) / 2;
    const negR = neutralOutside
      ? (radii.middleStart + radii.middleEnd) / 2
      : (radii.outerStart + radii.outerEnd) / 2;

    const result: { fromIdx: number; toIdx: number; path: string; head: string }[] = [];

    for (let i = 0; i < pos.length; i++) {
      const nextIdx = cw ? (i + 1) % neg.length : (i - 1 + neg.length) % neg.length;

      const posSeg = pos[i];
      const negSeg = neg[nextIdx];

      const posMidAngle = (posSeg.startAngle + posSeg.endAngle) / 2;
      const negMidAngle = (negSeg.startAngle + negSeg.endAngle) / 2;

      const [sx, sy] = polarToCartesian(posR, posMidAngle);
      const [ex, ey] = polarToCartesian(negR, negMidAngle);

      const midR = (posR + negR) / 2;
      const angleDiff = cw
        ? ((negMidAngle - posMidAngle + 2 * Math.PI) % (2 * Math.PI))
        : ((posMidAngle - negMidAngle + 2 * Math.PI) % (2 * Math.PI));
      const ctrlAngle = cw
        ? posMidAngle + angleDiff * 0.5
        : posMidAngle - angleDiff * 0.5;
      const [cx, cy] = polarToCartesian(midR, ctrlAngle);

      const path = `M${sx},${sy} Q${cx},${cy} ${ex},${ey}`;

      const tx = 2 * (ex - cx);
      const ty = 2 * (ey - cy);
      const len = Math.sqrt(tx * tx + ty * ty);
      const ux = tx / len;
      const uy = ty / len;
      const headLen = 6;
      const px = -uy;
      const py = ux;
      const h1x = ex - ux * headLen + px * headLen * 0.4;
      const h1y = ey - uy * headLen + py * headLen * 0.4;
      const h2x = ex - ux * headLen - px * headLen * 0.4;
      const h2y = ey - uy * headLen - py * headLen * 0.4;

      const head = `M${h1x},${h1y} L${ex},${ey} L${h2x},${h2y}`;

      result.push({ fromIdx: posSeg.perspectiveIndex, toIdx: negSeg.perspectiveIndex, path, head });
    }

    return result;
  }, [segments, radii, neutralOutside, direction]);

  const dimUnfocused = styles.dimUnfocused ?? 0.5;

  const arrowOpacity = (fromIdx: number, toIdx: number) => {
    if (focusAnimatingIdx != null) {
      if (fromIdx !== focusAnimatingIdx && toIdx !== focusAnimatingIdx) return 0;
    }
    if (selectedPerspectiveIdx != null) {
      if (fromIdx !== selectedPerspectiveIdx && toIdx !== selectedPerspectiveIdx
        && fromIdx !== hoveredPerspectiveIdx && toIdx !== hoveredPerspectiveIdx) {
        return 1 - dimUnfocused;
      }
    }
    return 1;
  };

  return (
    <g>
      {arrows.map((arrow, i) => (
        <g
          key={i}
          opacity={arrowOpacity(arrow.fromIdx, arrow.toIdx)}
          style={{ transition: 'opacity 200ms ease-in' }}
        >
          <path
            d={arrow.path}
            fill="none"
            stroke="#000"
            strokeWidth={1.5}
            strokeLinecap="round"
          />
          <path
            d={arrow.head}
            fill="none"
            stroke="#000"
            strokeWidth={1.5}
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </g>
      ))}
    </g>
  );
};
